package in.Arrays;

public class IntArrayExample {

	public static void main(String[] args) {
		// TODO Auto-generated method stub
		int[] num;
		num=new int[5];
		num[0]=1;
		num[1]=2;
		num[2]=3;
		num[3]=4;
		num[4]=5;
		for(int i=0;i<num.length;i++) {
			System.out.println(num[i]);
		}
		

	}

}
